@@ -912,1 +912,5 @@
-      __ bleu(cnt, tmp0, small_copy);
+      // For backward/conjoint copies, do not use the forward-style small_copy
+      // path below. It would violate memmove semantics on overlap.
+      if (!is_backward) {
+        __ bleu(cnt, tmp0, small_copy);
+      }
